t2dd  = (term1 + term2 + term3 + term4) / (l2 * delta) - c * t2d

t1d = t1d + dt * t1dd/2
t2d = t2d + dt * t2dd/2

t1b  <- t1
t2b  <- t2
t1db <- t1d
t2db <- t2d

